    if (error) throw error;
    return { id: announcementId, content } as Announcement;
};

export const deleteAnnouncement = async (announcementId: string): Promise<void> => {
    const { error } = await supabase.from('announcements').delete().eq('id', announcementId);
    if (error) throw error;
};

export const markAnnouncementAsRead = async (announcementId: string, userId: string): Promise<void> => {
    const { data } = await supabase.from('announcements').select('read_by').eq('id', announcementId).single();
    if (data) {
        const currentReadBy = data.read_by || [];
        if (!currentReadBy.some((r: any) => r.userId === userId)) {
            const updatedReadBy = [...currentReadBy, { userId, readAt: new Date().toISOString() }];
            const { error } = await supabase.from('announcements').update({ read_by: updatedReadBy }).eq('id', announcementId);
            if (error) throw error;
        }
    }
};

export const createDirectTask = async (task: Omit<DirectTask, 'id' | 'sentAt' | 'status' | 'isReadByEmployee'>): Promise<DirectTask> => {
    const newId = generateId();
    const dbTask = { id: newId, manager_id: task.managerId, employee_id: task.employeeId, content: task.content, sent_at: new Date().toISOString(), status: 'pending', is_read_by_employee: false };
    const { error } = await supabase.from('direct_tasks').insert(dbTask);
    if (error) throw error;
    return { ...task, id: newId, sentAt: dbTask.sent_at, status: 'pending', isReadByEmployee: false };
};

export const updateDirectTaskStatus = async (taskId: string, status: 'acknowledged' | 'rejected', rejectionReason?: string): Promise<void> => {
    const updates: any = { status };
    if (rejectionReason) updates.rejection_reason = rejectionReason;
    if (status === 'acknowledged') updates.acknowledged_at = new Date().toISOString();
    const { error } = await supabase.from('direct_tasks').update(updates).eq('id', taskId);
    if (error) throw error;
};

export const markDirectTaskAsRead = async (taskId: string): Promise<void> => {
    const { error } = await supabase.from('direct_tasks').update({ is_read_by_employee: true }).eq('id', taskId);
    if (error) throw error;
};

import React, { createContext, useState, useContext, ReactNode, useMemo, useCallback, useEffect, useRef } from 'react';
import { User, Report, Announcement, DirectTask } from '../types';
import * as api from '../services/apiService';

interface AppState {
    users: User[];
    reports: Report[];
    announcements: Announcement[];
    directTasks: DirectTask[];
}

interface DataContextType extends AppState {
    isDataLoading: boolean;
    isCloud: boolean;
    error: string | null;
    getUserById: (id: string) => User | undefined;
    addReport: (report: Omit<Report, 'id' | 'sequenceNumber' | 'status'>) => Promise<void>;
    updateReport: (updatedReport: Report) => Promise<void>;
    saveOrUpdateDraft: (draft: Partial<Report>) => Promise<void>;
    deleteReport: (reportId: string) => Promise<void>;
    markReportAsViewed: (reportId: string) => Promise<void>;
    markCommentAsRead: (reportId: string) => Promise<void>;
    addUser: (user: Omit<User, 'id'>) => Promise<void>;
    updateUser: (user: User) => Promise<void>;
    deleteUser: (userId: string) => Promise<void>;
    addAnnouncement: (content: string) => Promise<void>;
    updateAnnouncement: (announcementId: string, content: string) => Promise<void>;
    deleteAnnouncement: (announcementId: string) => Promise<void>;
    markAnnouncementAsRead: (announcementId: string, userId: string) => Promise<void>;
    addDirectTask: (task: Omit<DirectTask, 'id' | 'sentAt' | 'status' | 'isReadByEmployee'>) => Promise<void>;
    updateDirectTaskStatus: (taskId: string, status: 'acknowledged' | 'rejected', rejectionReason?: string) => Promise<void>;
    markDirectTaskAsRead: (taskId: string) => Promise<void>;
}

const DataContext = createContext<DataContextType | undefined>(undefined);

export const DataProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
    const [appState, setAppState] = useState<AppState>({ users: [], reports: [], announcements: [], directTasks: [] });
    const [isDataLoading, setIsDataLoading] = useState(true);
    const [isCloud, setIsCloud] = useState(false);
    const [error, setError] = useState<string | null>(null);

    // Ref to prevent state closure issues in callbacks
    const stateRef = useRef(appState);
    useEffect(() => { stateRef.current = appState; }, [appState]);

    const loadData = useCallback(async (silent = false) => {
        if (!silent) setIsDataLoading(true);
        try {
            const data = await api.fetchInitialData();
            setAppState({
                users: data.users,
                reports: data.reports,
                announcements: data.announcements,
                directTasks: data.directTasks
            });
            setIsCloud(data.isCloud);
        } catch (error: any) {
            console.error("Failed to load data:", error);
            setError(error.message || "فشل الاتصال بقاعدة البيانات.");
        } finally {
            if (!silent) setIsDataLoading(false);
        }
    }, []);

    // تفعيل التزامن الفوري الذكي
    useEffect(() => {
        loadData();

        const unsubscribe = api.subscribeToAllChanges((payload) => {
            console.log("Realtime Sync Payload:", payload);

            // تحديث البيانات فوراً صامتاً لضمان المزامنة
            loadData(true);

            // يمكن هنا إضافة منطق لمعالجة الـ Payload وتحديث جزء من الـ State فقط لزيادة السرعة
            // لكن loadData(true) هي الطريقة الأكثر موثوقية لضمان تطابق البيانات
        });

        return () => { unsubscribe(); };
    }, [loadData]);

    const getUserById = useCallback((id: string) => appState.users.find(u => u.id === id), [appState.users]);

    const performApiAction = useCallback(async (action: Promise<any>) => {
        try {
            await action;
            // لا حاجة لانتظار loadData هنا لأن الاشتراك اللحظي سيقوم بالمهمة
        } catch (error) {
            console.error("Action failed:", error);
            throw error;
        }
    }, []);

    const addReport = useCallback(async (report: Omit<Report, 'id' | 'sequenceNumber' | 'status'>) => performApiAction(api.createReport(report)), [performApiAction]);
    const updateReport = useCallback(async (updatedReport: Report) => performApiAction(api.updateReport(updatedReport)), [performApiAction]);
    const saveOrUpdateDraft = useCallback(async (draft: Partial<Report>) => performApiAction(api.saveOrUpdateDraft(draft)), [performApiAction]);
    const deleteReport = useCallback(async (reportId: string) => performApiAction(api.deleteReport(reportId)), [performApiAction]);
    const markReportAsViewed = useCallback(async (reportId: string) => performApiAction(api.markReportAsViewed(reportId)), [performApiAction]);
    const markCommentAsRead = useCallback(async (reportId: string) => performApiAction(api.markCommentAsRead(reportId)), [performApiAction]);
    const addUser = useCallback(async (user: Omit<User, 'id'>) => performApiAction(api.createUser(user)), [performApiAction]);
    const updateUser = useCallback(async (updatedUser: User) => performApiAction(api.updateUser(updatedUser)), [performApiAction]);
    const deleteUser = useCallback(async (userId: string) => performApiAction(api.deleteUser(userId)), [performApiAction]);
    const addAnnouncement = useCallback(async (content: string) => performApiAction(api.createAnnouncement(content)), [performApiAction]);
    const updateAnnouncement = useCallback(async (announcementId: string, content: string) => performApiAction(api.updateAnnouncement(announcementId, content)), [performApiAction]);
    const deleteAnnouncement = useCallback(async (announcementId: string) => performApiAction(api.deleteAnnouncement(announcementId)), [performApiAction]);
    const markAnnouncementAsRead = useCallback(async (announcementId: string, userId: string) => performApiAction(api.markAnnouncementAsRead(announcementId, userId)), [performApiAction]);
    const addDirectTask = useCallback(async (task: Omit<DirectTask, 'id' | 'sentAt' | 'status' | 'isReadByEmployee'>) => performApiAction(api.createDirectTask(task)), [performApiAction]);
    const updateDirectTaskStatus = useCallback(async (taskId: string, status: 'acknowledged' | 'rejected', rejectionReason?: string) => performApiAction(api.updateDirectTaskStatus(taskId, status, rejectionReason)), [performApiAction]);
    const markDirectTaskAsRead = useCallback(async (taskId: string) => performApiAction(api.markDirectTaskAsRead(taskId)), [performApiAction]);

    const value = useMemo(() => ({
        ...appState, isDataLoading, isCloud, error, getUserById, addReport, updateReport, saveOrUpdateDraft, deleteReport, markReportAsViewed,
        markCommentAsRead, addUser, updateUser, deleteUser, addAnnouncement, updateAnnouncement, deleteAnnouncement,
        markAnnouncementAsRead, addDirectTask, updateDirectTaskStatus, markDirectTaskAsRead
    }), [
        appState, isDataLoading, isCloud, error, getUserById, addReport, updateReport, saveOrUpdateDraft, deleteReport, markReportAsViewed,
        markCommentAsRead, addUser, updateUser, deleteUser, addAnnouncement, updateAnnouncement, deleteAnnouncement,
        markAnnouncementAsRead, addDirectTask, updateDirectTaskStatus, markDirectTaskAsRead
    ]);

    return (
        <DataContext.Provider value={value}>
            {children}
        </DataContext.Provider>
    );
};

export const useData = (): DataContextType => {
    const context = useContext(DataContext);
    if (!context) throw new Error('useData must be used within a DataProvider');
    return context;
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import { useData } from '../context/DataContext';
import { Role, Attachment, Report } from '../types';
import PlusIcon from './icons/PlusIcon';
import TrashIcon from './icons/TrashIcon';
import PaperclipIcon from './icons/PaperclipIcon';
import LogoutIcon from './icons/LogoutIcon';
import ReportView from './ReportView';
import NewReportIcon from './icons/NewReportIcon';
import InboxIcon from './icons/InboxIcon';
import Avatar from './Avatar';
import ProfileManagement from './ProfileManagement';
import UserCircleIcon from './icons/UserCircleIcon';
import ReportDetailModal from './ReportDetailModal';
import Toast from './Toast';
import MenuIcon from './icons/MenuIcon';
import ThemeToggle from './ThemeToggle';
import AppLogoIcon from './icons/AppLogoIcon';
import HomeIcon from './icons/HomeIcon';
import DirectTasksView from './DirectTasksView';
import ArchiveBoxIcon from './icons/ArchiveBoxIcon';
import ConfirmModal from './ConfirmModal';
import BellIcon from './icons/BellIcon';
import CameraIcon from './icons/CameraIcon';
import DocumentTextIcon from './icons/DocumentTextIcon';
import XMarkIcon from './icons/XMarkIcon';

const NOTIFICATION_SOUND_URL = "https://assets.mixkit.co/active_storage/sfx/2869/2869-preview.mp3";

const EmployeeDashboard: React.FC = () => {
    const { currentUser, logout } = useAuth();
    const { reports, directTasks, announcements, addReport } = useData();

    const [activeTab, setActiveTab] = useState('home');
    const [isSidebarOpen, setIsSidebarOpen] = useState(false);
    const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);
    const [selectedReport, setSelectedReport] = useState<Report | null>(null);
    const [toast, setToast] = useState<{message: string, type: 'info' | 'success'} | null>(null);
    const [notificationPermission, setNotificationPermission] = useState<NotificationPermission>('default');

    const fileInputRef = useRef<HTMLInputElement>(null);
    const cameraInputRef = useRef<HTMLInputElement>(null);

    // استخدام Refs لمراقبة التغييرات فورياً دون التسبب في تكرار الإشعارات
    const lastNotifiedTaskId = useRef<string | null>(null);
    const lastNotifiedCommentId = useRef<string | null>(null);
    const lastNotifiedAnnId = useRef<string | null>(null);

    const [reportForm, setReportForm] = useState<{
        tasks: { id: string, text: string }[],
        accomplished: string,
        notAccomplished: string,
        attachments: Attachment[]
    }>({
        tasks: [{ id: Date.now().toString(), text: '' }],
        accomplished: '',
        notAccomplished: '',
        attachments: []
    });

    useEffect(() => {
        if ('Notification' in window) {
            setNotificationPermission(Notification.permission);
        }
    }, []);

    const triggerNotification = async (title: string, body: string) => {
        // تشغيل صوت التنبيه فوراً
        const audio = new Audio(NOTIFICATION_SOUND_URL);
        audio.play().catch(e => console.log("Audio play blocked", e));

        // إظهار إشعار النظام (System Notification)
        if (Notification.permission === 'granted' && 'serviceWorker' in navigator) {
            const registration = await navigator.serviceWorker.ready;
            registration.showNotification(title, {
                body,
                icon: '/icon-192.png',
                badge: '/icon-192.png',
                vibrate: [300, 100, 300],
                tag: 'task-alert',
                requireInteraction: true // يبقى الإشعار حتى يتفاعل معه المستخدم
            } as any);
        } else if (Notification.permission === 'granted') {
            new Notification(title, { body, icon: '/icon-192.png' });
        }

        setToast({ message: body, type: 'info' });
    };

    // مراقبة التغييرات الفورية وإطلاق الإشعارات
    useEffect(() => {
        if (!currentUser) return;

        // 1. التحقق من المهام الجديدة
        const myPendingTasks = directTasks.filter(t => t.employeeId === currentUser.id && t.status === 'pending');
        if (myPendingTasks.length > 0) {
            const newestTask = myPendingTasks[0];
            if (newestTask.id !== lastNotifiedTaskId.current) {
                triggerNotification("مهمة جديدة واردة", newestTask.content.substring(0, 50) + "...");
                lastNotifiedTaskId.current = newestTask.id;
            }
        }

        // 2. التحقق من تعليقات المسؤول
        const myReportsWithNewComments = reports.filter(r => r.userId === currentUser.id && r.managerComment && !r.isCommentReadByEmployee);
        if (myReportsWithNewComments.length > 0) {
            const newestReport = myReportsWithNewComments[0];
            if (newestReport.id !== lastNotifiedCommentId.current) {
                triggerNotification("تعليق جديد من المسؤول", "قام المسؤول بالتعليق على أحد تقاريرك.");
                lastNotifiedCommentId.current = newestReport.id;
            }
        }

        // 3. التحقق من التوجيهات العامة
        if (announcements.length > 0) {
            const newestAnn = announcements[0];
            if (newestAnn.id !== lastNotifiedAnnId.current) {
                triggerNotification("توجيه إداري جديد", newestAnn.content.substring(0, 50) + "...");
                lastNotifiedAnnId.current = newestAnn.id;
            }
        }
    }, [directTasks, reports, announcements, currentUser]);

    const myReports = useMemo(() => 
        reports.filter(r => r.userId === currentUser?.id)
               .sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime())
    , [reports, currentUser]);

    const unreadTasksCount = useMemo(() => 
        directTasks.filter(t => t.employeeId === currentUser?.id && t.status === 'pending' && !t.isReadByEmployee).length
    , [directTasks, currentUser]);

    if (!currentUser) return null;

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = e.target.files;
        if (files) {
            Array.from(files).forEach((file: File) => {
                const reader = new FileReader();
                reader.onloadend = () => {
                    setReportForm(prev => ({
                        ...prev,
                        attachments: [...prev.attachments, {
                            name: file.name,
                            type: file.type,
                            size: file.size,
                            content: reader.result as string
                        }]
                    }));
                };
                reader.readAsDataURL(file);
            });
            e.target.value = '';
        }
    };

    const removeAttachment = (index: number) => {
        setReportForm(prev => ({
            ...prev,
            attachments: prev.attachments.filter((_, i) => i !== index)
        }));
    };

    const handleSubmitReport = async (e: React.FormEvent) => {
        e.preventDefault();
        const nonEmptyTasks = reportForm.tasks.filter(t => t.text.trim() !== '');
        if (nonEmptyTasks.length === 0) {
            setToast({ message: 'يرجى إضافة مهمة واحدة على الأقل.', type: 'info' });
            return;
        }

        const reportData = {
            userId: currentUser.id,
            date: new Date().toISOString().split('T')[0],
            day: new Intl.DateTimeFormat('ar-EG', { weekday: 'long' }).format(new Date()),
            tasks: nonEmptyTasks.map(t => ({ id: t.id, text: t.text })),
            accomplished: reportForm.accomplished,
            notAccomplished: reportForm.notAccomplished,
            attachments: reportForm.attachments
        };

        try {
            await addReport(reportData);
            setReportForm({
                tasks: [{ id: Date.now().toString(), text: '' }],
                accomplished: '',
                notAccomplished: '',
                attachments: []
            });
            setToast({ message: 'تم إرسال التقرير بنجاح!', type: 'success' });
            setActiveTab('archive');
        } catch (error) {
            setToast({ message: 'فشل إرسال التقرير.', type: 'info' });
        }
    };

    const NavItem: React.FC<{tabName: string; label: string; icon: React.ReactNode; count?: number}> = ({tabName, label, icon, count}) => {
        const isActive = activeTab === tabName;
        return (
             <button
                onClick={() => {
                    setActiveTab(tabName);
                    if (window.innerWidth < 768) setIsSidebarOpen(false);
                }}
                className={`flex items-center w-full px-4 py-3 text-sm font-medium transition-colors rounded-xl ${isActive ? 'bg-brand-light text-white shadow-lg shadow-brand-light/30' : 'text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700/50'}`}
            >
                {icon}
                <span className="mr-3">{label}</span>
                {count && count > 0 ? <span className="flex items-center justify-center w-5 h-5 mr-auto text-xs font-bold text-white bg-brand-accent-red rounded-full">{count}</span> : null}
            </button>
        );
    };

    const renderContent = () => {
        switch(activeTab) {
            case 'home':
                return (
                    <div className="space-y-6 animate-fade-in pb-20">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
                                <h3 className="text-lg font-bold text-gray-800 dark:text-gray-200 mb-4">ملخص الأداء</h3>
                                <div className="space-y-3">
                                    <div className="flex justify-between items-center p-3 bg-gray-50 dark:bg-gray-700/50 rounded-xl">
                                        <span className="text-gray-600 dark:text-gray-400 text-sm">إجمالي التقارير</span>
                                        <span className="font-bold text-brand-dark dark:text-gray-100">{myReports.length}</span>
                                    </div>
                                    <div className="flex justify-between items-center p-3 bg-gray-50 dark:bg-gray-700/50 rounded-xl">
                                        <span className="text-gray-600 dark:text-gray-400 text-sm">مهام واردة</span>
                                        <span className="font-bold text-brand-dark dark:text-gray-100">{unreadTasksCount}</span>
                                    </div>
                                </div>
                            </div>
                             <div className="bg-gradient-to-br from-brand-light to-brand-dark p-6 rounded-2xl shadow-lg flex flex-col justify-center items-center text-center text-white">
                                <AppLogoIcon className="w-16 h-16 mb-2 opacity-90" />
                                <h3 className="text-xl font-bold">أهلاً بك، {currentUser.fullName.split(' ')[0]}</h3>
                                <p className="text-white/80 text-xs mt-1">المزامنة الفورية مفعلة الآن</p>
                                <button onClick={() => setActiveTab('new-report')} className="mt-4 px-6 py-2 bg-white text-brand-dark rounded-full transition-transform active:scale-95 text-sm font-bold shadow-md">إنشاء تقرير اليوم</button>
                            </div>
                        </div>

                        <div className="flex items-center justify-between px-1">
                            <h3 className="text-lg font-bold text-gray-800 dark:text-gray-200">التقارير الأخيرة</h3>
                            <button onClick={() => setActiveTab('archive')} className="text-brand-light text-sm font-semibold">عرض الكل</button>
                        </div>
                        <div className="space-y-4">
                            {myReports.slice(0, 3).map(r => (
                                <ReportView key={r.id} report={r} user={currentUser} viewerRole={Role.EMPLOYEE} onClick={() => setSelectedReport(r)} />
                            ))}
                        </div>
                    </div>
                );
            case 'new-report':
                return (
                    <form onSubmit={handleSubmitReport} className="bg-white dark:bg-gray-800 p-5 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 space-y-6 animate-fade-in pb-20">
                        <div className="flex items-center justify-between">
                            <h3 className="text-lg font-bold text-brand-dark dark:text-gray-100 flex items-center">
                                <NewReportIcon className="w-6 h-6 ml-2" />
                                تقرير جديد
                            </h3>
                            <span className="text-xs text-gray-500">{new Date().toLocaleDateString('ar-EG')}</span>
                        </div>
                        <div className="space-y-4">
                            <label className="block text-sm font-bold text-gray-700 dark:text-gray-300">المهام اليومية</label>
                            {reportForm.tasks.map((task, index) => (
                                <div key={task.id} className="flex gap-2">
                                    <input
                                        type="text"
                                        value={task.text}
                                        onChange={(e) => setReportForm(prev => ({ ...prev, tasks: prev.tasks.map(t => t.id === task.id ? { ...t, text: e.target.value } : t) }))}
                                        placeholder={`المهمة ${index + 1}...`}
                                        className="flex-grow px-3 py-3 border border-gray-200 dark:border-gray-600 rounded-xl bg-gray-50 dark:bg-gray-700 dark:text-gray-200 focus:ring-2 focus:ring-brand-light/50 outline-none"
                                        required
                                    />
                                    {reportForm.tasks.length > 1 && (
                                        <button type="button" onClick={() => setReportForm(prev => ({ ...prev, tasks: prev.tasks.filter(t => t.id !== task.id) }))} className="p-2 text-red-500 active:scale-90 transition-transform">
                                            <TrashIcon className="w-6 h-6" />
                                        </button>
                                    )}
                                </div>
                            ))}
                            <button type="button" onClick={() => setReportForm(prev => ({ ...prev, tasks: [...prev.tasks, { id: Date.now().toString(), text: '' }] }))} className="text-brand-light text-sm font-bold flex items-center py-2 px-1">
                                <PlusIcon className="w-4 h-4 ml-1" /> إضافة مهمة أخرى
                            </button>
                        </div>
                        <div className="space-y-4">
                            <label className="block text-sm font-bold text-gray-700 dark:text-gray-300">التفاصيل</label>
                            <textarea placeholder="ما تم إنجازه..." value={reportForm.accomplished} onChange={e => setReportForm(p => ({...p, accomplished: e.target.value}))} rows={3} className="w-full px-3 py-3 border border-gray-200 dark:border-gray-600 rounded-xl bg-gray-50 dark:bg-gray-700 dark:text-white outline-none" />
                            <textarea placeholder="المعوقات (إن وجدت)..." value={reportForm.notAccomplished} onChange={e => setReportForm(p => ({...p, notAccomplished: e.target.value}))} rows={2} className="w-full px-3 py-3 border border-gray-200 dark:border-gray-600 rounded-xl bg-gray-50 dark:bg-gray-700 dark:text-white outline-none" />
                        </div>

                        <div className="space-y-3 pt-4 border-t dark:border-gray-700">
                            <label className="block text-sm font-bold text-gray-700 dark:text-gray-300">المرفقات</label>
                            <div className="flex gap-2">
                                <button 
                                    type="button"
                                    onClick={() => fileInputRef.current?.click()}
                                    className="flex-1 flex flex-col items-center justify-center p-3 text-xs font-bold text-gray-600 dark:text-gray-300 bg-gray-50 dark:bg-gray-700 border border-gray-200 dark:border-gray-600 rounded-xl active:bg-gray-100"
                                >
                                    <PaperclipIcon className="w-6 h-6 mb-1 text-brand-light" />
                                    إرفاق ملف
                                </button>
                                <button 
                                    type="button"
                                    onClick={() => cameraInputRef.current?.click()}
                                    className="flex-1 flex flex-col items-center justify-center p-3 text-xs font-bold text-gray-600 dark:text-gray-300 bg-gray-50 dark:bg-gray-700 border border-gray-200 dark:border-gray-600 rounded-xl active:bg-gray-100"
                                >
                                    <CameraIcon className="w-6 h-6 mb-1 text-brand-light" />
                                    الكاميرا
                                </button>
                            </div>
                            <input type="file" ref={fileInputRef} onChange={handleFileChange} multiple accept="image/*,application/pdf" className="hidden" />
                            <input type="file" ref={cameraInputRef} onChange={handleFileChange} accept="image/*" capture="environment" className="hidden" />

                            {reportForm.attachments.length > 0 && (
                                <div className="flex flex-wrap gap-2 pt-2">
                                    {reportForm.attachments.map((file, index) => (
                                        <div key={index} className="relative w-16 h-16 border dark:border-gray-600 rounded-lg overflow-hidden bg-gray-50 dark:bg-gray-800">
                                            {file.type.startsWith('image/') ? (
                                                <img src={file.content} alt={file.name} className="w-full h-full object-cover" />
                                            ) : (
                                                <div className="w-full h-full flex items-center justify-center">
                                                    <DocumentTextIcon className="w-8 h-8 text-brand-light" />
                                                </div>
                                            )}
                                            <button 
                                                type="button"
                                                onClick={() => removeAttachment(index)}
                                                className="absolute -top-1 -left-1 p-1 bg-red-500 text-white rounded-full shadow-md"
                                            >
                                                <XMarkIcon className="w-3 h-3" />
                                            </button>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>

                        <div className="pt-4">
                            <button type="submit" className="w-full py-4 bg-brand-light text-white rounded-xl active:scale-95 transition-all font-bold shadow-lg shadow-brand-light/30">إرسال التقرير النهائي</button>
