                        {myReports.length === 0 && <div className="text-center py-10 text-gray-500">لا يوجد تقارير سابقة</div>}
                    </div>
                );
            case 'profile': return <div className="pb-20"><ProfileManagement user={currentUser} /></div>;
            default: return null;
        }
